var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"아케론은 다신 지구로 돌아와 땅을 밟을 예정이 없는 구제불가판정의 중죄수들을 수감하는 곳입니다.","JPN":"アケロンは二度と地球に戻る予定のない、救済不可と判断された重罪人を収容するところです。","ENG":"Acheron holds irredeemable felons who have no future of ever setting foot on earth again.","TWN":"那些被認為無可救藥的，再也沒希望回到地球的重犯才會被關進黃泉。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"하지만 그런 죄수들 중에서도 특별위험군으로 분류된 죄수들은 큐브 아케론의 가장자리에 위치한 수감동인 엣지존에 수감되죠.","JPN":"しかし、そんな囚人の中でも特別危険群として分類された囚人は、キューブアケロンの端に位置する収容棟、エッジゾーンに収監されます。","ENG":"However, even among those prisoners, some are categorized as special and are imprisoned in the edge zone of the Acheron Cube.","TWN":"而這些囚犯中歸類為特殊危險群體的囚犯會被關進位於黃泉魔方的邊緣區。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"가장자리의 감옥이라…","JPN":"端の監獄か……","ENG":"Prisons on the edge...","TWN":"邊緣地區的監獄……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"보통 탈출하면 제일 곤란한 녀석들은 가장 깊숙한 곳에 처박아 넣지 않나?","JPN":"本来、脱走されて困る奴らは施設の中枢に閉じ込めるはずでは？","ENG":"Don't they normally place dangerous prisoners in the deepest prisons?","TWN":"通常不是會把那些最棘手的傢伙關進最深處嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"여긴 빠져나갈 곳 없는 우주 한복판이니까요.","JPN":"ここは脱出不可能な、宇宙の真ん中ですよ。","ENG":"Well, we are literally in space with nowhere to escape.","TWN":"但這裡是無處可逃的太空。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"수감자가 문제를 일으키는 순간, 수감동 자체를 아케론에서 분리 사출시키는 겁니다.","JPN":"収監者が問題を起こした瞬間、収容棟自体をアケロンから分離し、射出するんです。","ENG":"As soon as a prisoner stirs up trouble, they can detach and launch the whole section from Acheron.","TWN":"一旦囚犯鬧事，他的牢房就會從黃泉分離並彈出。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"효과적인 방식이긴 하군. 제아무리 그 녀석이라도 우주에서 숨을 쉬진 못하겠지.","JPN":"効果的な方法ではあるな。いくらあいつでも、宇宙で呼吸をすることはできまい。","ENG":"It certainly sounds effective. Not even she would be able to breathe in space.","TWN":"確實很有效。再厲害的人也沒辦法在太空中自由呼吸。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이 앞이 그 수감동으로 이어지는 길인가?","JPN":"ここがその収容棟に繋がる道なのか？","ENG":"Is this the path to that section?","TWN":"那些牢房是在前方嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"예, 하지만 역시 차단문이 내려져 있군요.","JPN":"はい、でもやはりシャッターが降りていますね。","ENG":"Yes. But, as expected, it's blocked.","TWN":"是的，但果然被隔離門隔開了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"조금 번거롭긴 해도 환풍구를 통해 이동하는 편이…","JPN":"少し面倒ですが、ダクトを通じて移動した方が……","ENG":"It may be a hassle, but it might be better to move through the vents–","TWN":"雖然有些麻煩，但只能透過通風口移動了……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그럴 시간 없다.","JPN":"そんな暇はない。","ENG":"No time for that.","TWN":"沒那麼多時間。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"…성급하시군요.","JPN":"……せっかちですね。","ENG":"...How impatient.","TWN":"……你也太沒耐心了。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"경비로봇들이 움직일 겁니다.","JPN":"警備ロボットが作動してしまいますよ。","ENG":"The security robots are going to activate.","TWN":"警衛機器人馬上會前來。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"가로막는 게 뭐가 됐건, 기어서 이동하는 것보단 빠르겠지.","JPN":"道を塞ぐものが何であろうと、這って移動するよりは速いだろう。","ENG":"Whatever blocks our way, it'll be faster than crawling.","TWN":"不管被什麼東西阻攔，總比在通風口通道裡爬著前進要快吧。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"괜히 휘말릴 필요 없으니 숨어있어라.","JPN":"お前を巻き込む必要はない。隠れていろ。","ENG":"You don't need to get caught up in it. Hide.","TWN":"你沒必要淌這個渾水，找個地方躲藏起來。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PRIME_NPC_PRISON_MECH","text":{"KOREA":"허가되지 않은 침입자 감지.","JPN":"侵入者を感知。","ENG":"Unauthorized intruder detected.","TWN":"發現入侵者。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L27_1","type":"dialog","speaker":"PRIME_NPC_PRISON_MECH","text":{"KOREA":"등록되지 않은 죄수- 코핀 컴퍼니의 힐데.","JPN":"未登録の囚人－コフィンカンパニーのヒルデ。 ","ENG":"Unregistered prisoner - Hilde from Coffin Company.","TWN":"未登記的囚犯——科芬公司的希爾德。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L28_1","type":"dialog","speaker":"PRIME_NPC_PRISON_MECH","text":{"KOREA":"고등급 카운터 진압 시퀀스로 전환.","JPN":"高ランクカウンター鎮圧シーケンスに転換。","ENG":"High-Grade Counter suppression sequence activated.","TWN":"轉換為高級制裁者鎮壓模式。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L29_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"벌써 내 정체를 눈치 챈 건가? 바깥에도 눈에 있는 모양이군.","JPN":"もう私の正体に気づいたのか？　外にも目があるようだな。","ENG":"You found out my identity already? There must be eyes watching from outside as well.","TWN":"我的身分已經被識破了？看來外面也有眼睛在看。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"하지만 여기까지 온 이상 상관없다.","JPN":"だがここまで来た以上、構わない。","ENG":"But it doesn't matter since I'm already here.","TWN":"既然已經到這一步就無所謂了。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PRIME_NPC_PRISON_MECH","text":{"KOREA":"보안 프로토콜 최고 레벨. 처벌 모드 가동.","JPN":"保安プロトコル、最高レベル。処罰モードを起動。","ENG":"Maximum level security protocol. Penalty mode activated.","TWN":"啟動安全協定最高等級處罰模式。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};